55	const PROCESSING_FEE = 5;
56	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
57	
58	const EPSILON = 1e-9;
59	
60	const roundUp = (n: number): number => Math.ceil(n - EPSILON);
61	
62	const ITEM_BASE_PREMIUMS: Record<string, number> = {
63	  sword: 100,
64	  amulet: 60,
65	  staff: 80,
66	  potion: 40,
67	  rune: 25,
68	};
69	
70	const itemPremiumWithFirstInsurance = (item: Item): number => {
71	  const base = ITEM_BASE_PREMIUMS[item.type] ?? 0;
72	  return base + base * FIRST_INSURANCE_SURCHARGE_RATE;
73	};
74	
75	const quotePremium = (items: Item[]): number => {
76	  const policyTotal = items.reduce(
77	    (sum, item) => sum + itemPremiumWithFirstInsurance(item),
78	    0,
79	  );
80	  return roundUp(policyTotal) + PROCESSING_FEE;
81	};
82	
83	export const processScenario = (scenario: Scenario): ScenarioResult => {
84	  const results: StepResult[] = scenario.steps.map((step) => {
85	    if (step.op === "quote") {
86	      return { premium: quotePremium(step.items) };
87	    }
88	    return { payout: 0, remainingCap: 0 };
89	  });
90	  return { results };
91	};
